import pytest

from your_module import hex_to_rgb


@pytest.mark.parametrize(
    "hex_value, expected",
    [
        ("#000000", (0, 0, 0)),
        ("#ffffff", (255, 255, 255)),
        ("#FFFFFF", (255, 255, 255)),
        ("#1a2b3c", (26, 43, 60)),
        ("1a2b3c", (26, 43, 60)),  # no leading #
        ("#ABCDEF", (171, 205, 239)),
    ],
)
def test_hex_to_rgb_happy_path(hex_value, expected):
    assert hex_to_rgb(hex_value) == expected


@pytest.mark.parametrize(
    "hex_value, expected",
    [
        ("#000", (0, 0, 0)),          # short form is not supported; parses as 00, 00, ''
        ("", ()),                     # no chars -> empty tuple
        ("#", ()),                    # stripped to empty string
        ("#12345", None),             # invalid length / incomplete last chunk
    ],
)
def test_hex_to_rgb_edge_cases(hex_value, expected):
    if expected is None:
        with pytest.raises(ValueError):
            hex_to_rgb(hex_value)
    else:
        assert hex_to_rgb(hex_value) == expected


@pytest.mark.parametrize(
    "hex_value, exc_type",
    [
        ("#12", ValueError),          # too short for 3 pairs
        ("#gggggg", ValueError),      # invalid hex digits
        ("#12zz34", ValueError),      # invalid hex digits in middle
        (None, AttributeError),       # not a string
        (123456, AttributeError),     # not a string
    ],
)
def test_hex_to_rgb_error_cases(hex_value, exc_type):
    with pytest.raises(exc_type):
        hex_to_rgb(hex_value)
